function mrqj($s,$m='',$x=array()){header('Content-Type: application/json');$p=array('status'=>$s);if($m!=='')$p['error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function mrqh($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function mrqn($v,$d=5){return number_format((float)$v,$d,',','.');}
function mrqqty($v){return (float)str_replace(',','.',trim((string)$v));}
function mrq_next_no($date){global $db;$prefix='MR'.date('Ym',strtotime($date?:date('Y-m-d')));$r=$db->fetch("SELECT requirement_no FROM erp_material_requirement WHERE requirement_no LIKE ? ORDER BY requirement_no DESC LIMIT 1",array($prefix.'%'));$n=1;if($r&&preg_match('/(\d{5})$/',$r->requirement_no,$m))$n=(int)$m[1]+1;return $prefix.sprintf('%05d',$n);}
function mrq_stock($code,$plant=''){global $db;$p=array($code);$w=" WHERE kode=? AND COALESCE(qty_sisa,0)>0 AND stock_type='UNRESTRICTED' ";if($plant!==''){$w.=" AND plant_id=(SELECT id FROM erp_plant WHERE plant_code=? LIMIT 1) ";$p[]=$plant;}$r=$db->fetch("SELECT SUM(COALESCE(qty_sisa,0)) qty FROM stock_layer $w",$p);return $r?(float)$r->qty:0;}
function mrq_item($code){global $db;return $db->fetch("SELECT kd_barang,nm_barang,satuan,type FROM barang WHERE kd_barang=? LIMIT 1",array($code));}
function mrq_filters_get(){return array('from'=>isset($_GET['tgl_awal'])&&$_GET['tgl_awal']!==''?$_GET['tgl_awal']:date('Y-m-01'),'to'=>isset($_GET['tgl_akhir'])&&$_GET['tgl_akhir']!==''?$_GET['tgl_akhir']:date('Y-m-t'),'status'=>isset($_GET['status'])?trim($_GET['status']):'','type'=>isset($_GET['type'])?trim($_GET['type']):'','plant'=>isset($_GET['plant'])?trim($_GET['plant']):'','keyword'=>isset($_GET['keyword'])?trim($_GET['keyword']):'');}
function mrq_where($f,&$p){$w=" WHERE h.requirement_date BETWEEN ? AND ? ";$p[]=$f['from'];$p[]=$f['to'];if($f['status']!==''){$w.=" AND h.status=? ";$p[]=$f['status'];}if($f['type']!==''){$w.=" AND h.requirement_type=? ";$p[]=$f['type'];}if($f['plant']!==''){$w.=" AND h.plant_code=? ";$p[]=$f['plant'];}if($f['keyword']!==''){$kw='%'.$f['keyword'].'%';$w.=" AND (h.requirement_no LIKE ? OR h.source_mrp_no LIKE ? OR h.source_production_order_no LIKE ? OR h.source_ref LIKE ? OR d.material_code LIKE ? OR d.material_name LIKE ? OR d.source_ref LIKE ? OR d.parent_material_code LIKE ?) ";for($i=0;$i<8;$i++)$p[]=$kw;}return $w;}

