    foreach($rows as $r){$qty=(float)($r->remaining_qty>0?$r->remaining_qty:$r->required_qty);$lines[]=array('material_code'=>$r->material_code,'material_name'=>$r->material_name,'material_type'=>'','required_date'=>$h->start_date?:date('Y-m-d'),'required_qty'=>$qty,'available_stock'=>mrq_stock($r->material_code,$h->plant),'uom'=>$r->uom,'source_type'=>'PRODUCTION_ORDER','source_ref'=>$h->no_production_order,'source_line_id'=>$r->id_material,'parent_material_code'=>$h->material_code,'storage_location'=>$r->storage_location,'procurement_type'=>'IN_HOUSE','remarks'=>'Requirement from production order');}
